import { useEffect, useRef, useState } from "react";

const ASCII_CHARS = "@#S%?*+;:,. ";
const charAspect = 2;

export default function App() {
  const canvasRef = useRef(null);

  const [ascii, setAscii] = useState('');
  const[image, setImage] = useState(null);
  const [targetWidth, setTargetWidth] = useState(120);
  const [isColor, setIsColor] = useState(true);

  useEffect(() => {
    if (image) {
      convertToAscii(image);
    }
  }, [targetWidth, isColor]);

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const img = new Image();
    img.src = URL.createObjectURL(file);

    img.onload = () => {
      setImage(img);
      convertToAscii(img);
    };
  };

  const convertToAscii = (img) => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");


    const scale = img.height / img.width;
    const targetHeight = Math.round(targetWidth * scale);

    canvas.width = targetWidth;
    canvas.height = targetHeight;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const srcW = img.width;
    const srcH = img.height;

    const srcAspect = srcW / srcH;
    const dstAspect = canvas.width / canvas.height;

    let sx = 0, sy = 0, sw = srcW, sh = srcH;
    let dx = 0, dy = 0, dw = canvas.width, dh = canvas.height;

    if (srcAspect > dstAspect) {
      dh = dw / srcAspect;
      dy = (canvas.height - dh) / 2;
    } else {
      dw = dh * srcAspect;
      dx = (canvas.width - dw) / 2;
    }

    ctx.drawImage(
      img,
      sx, sy, sw, sh,
      dx, dy, dw, dh
    );
    const imgData = ctx.getImageData(
      0, 0, canvas.width, canvas.height
    );

    const data = imgData.data;

    let result = [];
    for (let y = 0; y < canvas.height; y += charAspect) {
      for (let x = 0; x < canvas.width; x++) {
        const i = (y * canvas.width + x) * 4;
        const r = data[i];
        const g = data[i + 1];
        const b = data[i + 2];

        const brightness = (r + g + b) / 3;
        const char = ASCII_CHARS[
          Math.floor((brightness / 255) * (ASCII_CHARS.length - 1))
        ];

        if (isColor) {
          result.push(
            `<span style="color: rgb(${r}, ${g}, ${b})">${char}</span>`
          );
      } else {
        result.push(char);
      }
    }
      result.push(isColor ? "<br/>" : "\n");
    }

    setAscii(result.join(""));
  };

   return (
    <div style={{ padding: 20 }}>
      <h1>ASCII Art Generator</h1>        

      <input type="file" accept="image/*" onChange={handleImageUpload} />

      <div style={{ margin: "10px 0" }}>
        <label>
          Width: {targetWidth}
          <input
            type="range"
            min="40"
            max="300"
            step="10"
            value={targetWidth}
            onChange={(e) => setTargetWidth(+e.target.value)}
          />
        </label>
      </div>

      <div style={{ marginBottom: 10}}>
        <label>
          <input
            type="checkbox"
            checked={isColor}
            onChange={(e) => setIsColor(e.target.checked)}
          />
          {" "}Color ASCII
        </label>
      </div>

      <canvas ref={canvasRef} style={{ display: "none" }} />

      <pre
        style={{
          fontFamily: "monospace",
          fontSize: "6px",
          lineHeight: "6px",
          whiteSpace: "pre",
        }}
         dangerouslySetInnerHTML={{ __html: ascii }}
      />
    </div>
  );
}
